}

try {
  // Propagate upstream error
  if (items.length === 1 && (items[0].json._error === true || items[0].json.error)) {
    const it = items[0].json;
    // HTTP Request node sends status code on error
    const httpErr = it.statusCode ? `HTTP ${it.statusCode}: ${it.message || JSON.stringify(it).substring(0,200)}` : null;
    const nestedMsg = (it.error && typeof it.error === 'object') ? (it.error.message || it.error.description || JSON.stringify(it.error).substring(0,200)) : null;
    const errMsg = httpErr || it.message || (typeof it.error === 'string' ? it.error : nestedMsg) || it.description || 'Google Sheets error';
    return [{ json: { _error: true, error: errMsg, step: 'GS Read Clients' } }];
  }

  const body = $('Webhook').first().json.body || $('Webhook').first().json;
  const topic = body.topic || '';
  const filters = body.filters || '';

  // Parse GS API HTTP response: {values: [[header, cols...], [row1...], ...]}
  // OR legacy GS node format: items is array of row objects with header keys
  let clients = [];
  if (items.length === 1 && items[0].json.values) {
    // HTTP Request to Google Sheets API: response has {values: [[header],[row1],[row2],...]}
    const rows = items[0].json.values || [];
    if (rows.length < 2) {
      return [{ json: { _error: true, error: 'Empty spreadsheet or no data rows', step: 'GS Read Clients' } }];
    }
    const headers = rows[0]; // first row = column headers
    clients = rows.slice(1).map((row, i) => {
      const obj = { _idx: i };
      headers.forEach((h, j) => { obj[h] = row[j] || ''; });
      return obj;
    });
  } else {
    // Legacy GS node format: each item is one row
    clients = items.map((item, i) => ({ _idx: i, ...item.json }));
  }

  const clientsStr = clients.map(c =>
    `${c._idx}: Имя=${c['Имя']||c['name']||c['Name']||'?'}, Email=${c['Email']||c['email']||''}, Компания=${c['Компания']||c['company']||''}, Интересы=${c['Интересы']||c['interests']||''}`
  ).join('\n');

  const prompt = `Ты маркетинговый ассистент. Выбери клиентов из списка, наиболее подходящих для кампании на тему: "${topic}".
${filters ? `Дополнительные критерии: ${filters}` : ''}
Список клиентов:
${clientsStr}

Верни ТОЛЬКО валидный JSON (без комментариев):
{
  "selected_indices": [0, 2, 5],
  "subject": " {topic}"
  "template": "Уважаемая(ый) {name}!\\n\\nМы рады предложить Вам..."
}

Выбери до 50 наиболее подходящих клиентов. Шаблон письма - на русском языке.`;

  return [{ json: { prompt, clients, topic, filters } }];
} catch(e) {
  return [{ json: { _error: true, step: "Prepare Prompt", detail: e.message } }];
}

try {
  // Propagate errors from Prepare Prompt (Demo Clients / GS Read Clients)
  const prepareData = $('Prepare Prompt').first().json;
  if (prepareData._error === true) return [{ json: prepareData }];

  const item = items[0].json;
  const allClients = prepareData.clients || [];

  // Check if OpenAI node failed (onError: continueRegularOutput puts error in item.error)
  if (item.error !== undefined && !item.choices) {
    const errMsg = typeof item.error === 'string'
      ? item.error
      : (item.error && (item.error.message || item.error.description)) || 'OpenAI request failed';
    return [{ json: { _error: true, step: "OpenAI Select", detail: errMsg } }];
  }

  let selected = [];
  let template = '';

  const rawData = item.data || item;
  let parsed = typeof rawData === 'string' ? JSON.parse(rawData) : rawData;
  let content = (parsed.choices && parsed.choices[0] && parsed.choices[0].message && parsed.choices[0].message.content)
    ? parsed.choices[0].message.content
    : JSON.stringify(parsed);

  // Strip markdown code fences: model sometimes wraps JSON in ```json...```
  content = content.trim();
  if (content.startsWith('`')) {
    content = content.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?```\s*$/, '').trim();
  }

  const result = JSON.parse(content);
  const indices = result.selected_indices || [];
  template = result.template || '';
  selected = indices.map(i => allClients[i]).filter(Boolean);

  if (selected.length === 0) {
    selected = allClients.slice(0, 5);
    template = template || `\u0423\u0432\u0430\u0436\u0430\u0435\u043c\u044b\u0439 {name}! \u041f\u0440\u0438\u0433\u043b\u0430\u0448\u0430\u0435\u043c \u0432\u0430\u0441 \u043f\u0440\u0438\u043d\u044f\u0442\u044c \u0443\u0447\u0430\u0441\u0442\u0438\u0435 \u0432 \u043d\u0430\u0448\u0435\u0439 \u043a\u0430\u043c\u043f\u0430\u043d\u0438\u0438: ${prepareData.topic}`;
  }

  // Normalize client keys: always expose 'name' and 'email' for downstream nodes
  selected = selected.map(c => ({
    ...c,
    name: c['\u0418\u043c\u044f'] || c['\u0424\u0418\u041e'] || c['name'] || c['Name'] || c['\u0418\u043c\u044f \u043a\u043b\u0438\u0435\u043d\u0442\u0430'] || '',
    topic: prepareData.topic||'',
    email: c['Email'] || c['email'] || c['\u042d\u043b\u0435\u043a\u0442\u0440\u043e\u043d\u043d\u0430\u044f \u043f\u043e\u0447\u0442\u0430'] || '',
  }));

  return [{ json: { clients: selected, template, count: selected.length } }];
} catch(e) {
  return [{ json: { _error: true, step: "Parse Response", detail: e.message } }];
}

try {
  // Try to find an existing template for the topic
  const parseData = $('Parse Response').first().json;
  if (parseData._error) return [{ json: parseData }];

  const topic = ($('Webhook').first().json.body || $('Webhook').first().json).topic || '';
  let template = parseData.template || '';

  // Look for matching template in Google Sheets "Шаблоны рассылки"
  let templateRows = [];
  try {
    const gsResp = $('GS Read Templates').first().json;
    if (gsResp && gsResp.values && gsResp.values.length > 1) {
      // HTTP API format: {values: [[header,...],[row1,...],...]
      const hdrs = gsResp.values[0];
      templateRows = gsResp.values.slice(1).map(row => {
        const obj = {};
        hdrs.forEach((h, j) => { obj[h] = row[j] || ''; });
        return obj;
      });
    } else {
      templateRows = $('GS Read Templates').all().map(i => i.json);
    }
  } catch(e) { templateRows = []; }

  const found = templateRows.find(row => {
    const sheetTopic = row['Тема'] || row['тема'] || '';
    return sheetTopic && topic && sheetTopic.toLowerCase().includes(topic.toLowerCase().slice(0, 20));
  });

  if (found) {
    template = found['Шаблон'] || found['шаблон'] || template;
  }

  return [{ json: { ...parseData, topic, template } }];
} catch(e) {
  return [{ json: { _error: true, step: "Merge Template", detail: e.message } }];
}
